// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.Random;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class ScopeRandomizedCampaignTest {

	@Test
	void primitiveStoresMatchOneHundredThirtyFiveThousandReferenceSeeds() {
		runPrimitiveCampaign(61, 100_000, 0x5905_0064L);
		runPrimitiveCampaign(127, 25_000, 0x5905_0128L);
		runPrimitiveCampaign(383, 10_000, 0x5905_0383L);
	}

	@Test
	void tenThousandAcceptedSequencesMatchSlowAndFullRebuildFacts() {
		Random random = new Random(0x5905_10_000L);
		for (int iteration = 0; iteration < 10_000; iteration++) {
			String shared = "shared" + random.nextInt(17);
			String leftName = "left" + random.nextInt(31);
			String rightName = "right" + random.nextInt(31);
			StatementPattern left = pattern(shared, leftName);
			StatementPattern right = pattern(shared, rightName);
			Filter filter = new Filter(new Join(left, right), Var.of(leftName));
			QueryRoot root = new QueryRoot(filter);

			ScopeAnalysis before = ScopeAnalysis.analyze(root);
			assertFastSlowRootParity(root, before);
			ScopeSafeRewriter rewriter = new ScopeSafeRewriter(root, before);
			assertThat(rewriter.moveFilterBelowJoinLeft(filter)).as("sequence %s", iteration).isTrue();
			ScopeAnalysis repaired = rewriter.analysis();
			assertFastSlowRootParity(root, repaired);

			ScopeAnalysis rebuilt = ScopeAnalysis.analyze(root);
			assertExactRootParity(root, repaired, rebuilt);
			rebuilt.close();
			repaired.close();
		}
	}

	private static void runPrimitiveCampaign(int symbols, int iterations, long seed) {
		Random random = new Random(seed);
		FactIndex facts = FactIndex.allocate(4, symbols);
		int words = facts.wordCount();
		long lastWordMask = symbols % Long.SIZE == 0 ? -1L : (1L << symbols % Long.SIZE) - 1L;
		long[] left = new long[words];
		long[] right = new long[words];
		for (int iteration = 0; iteration < iterations; iteration++) {
			facts.clear(4);
			for (int word = 0; word < words; word++) {
				long mask = word + 1 == words ? lastWordMask : -1L;
				left[word] = random.nextLong() & mask;
				right[word] = random.nextLong() & mask;
				facts.setWord(SemanticMask.MAY_BIND, 0, word, left[word]);
				facts.setWord(SemanticMask.MUST_BIND, 1, word, right[word]);
			}
			facts.union(SemanticMask.SCOPE_OUT, 2, SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1);
			facts.intersect(SemanticMask.READS, 3, SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1);

			boolean intersects = false;
			boolean leftSubset = true;
			for (int word = 0; word < words; word++) {
				assertThat(facts.word(SemanticMask.SCOPE_OUT, 2, word)).isEqualTo(left[word] | right[word]);
				assertThat(facts.word(SemanticMask.READS, 3, word)).isEqualTo(left[word] & right[word]);
				intersects |= (left[word] & right[word]) != 0L;
				leftSubset &= (left[word] & ~right[word]) == 0L;
			}
			assertThat(facts.intersects(SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1))
					.isEqualTo(intersects);
			assertThat(facts.subsetOf(SemanticMask.MAY_BIND, 0, SemanticMask.MUST_BIND, 1))
					.isEqualTo(leftSubset);
		}
	}

	private static void assertFastSlowRootParity(QueryRoot root, ScopeAnalysis fast) {
		SlowReferenceAnalyzer slow = SlowReferenceAnalyzer.analyze(root);
		for (SemanticMask mask : SemanticMask.values()) {
			assertThat(fast.names(mask, root)).isEqualTo(slow.names(mask, root));
		}
	}

	private static void assertExactRootParity(QueryRoot root, ScopeAnalysis first, ScopeAnalysis second) {
		for (SemanticMask mask : SemanticMask.values()) {
			assertThat(first.names(mask, root)).isEqualTo(second.names(mask, root));
		}
		assertScalarParity(root, first, second);
		assertScalarParity(root.getArg(), first, second);
	}

	private static void assertScalarParity(QueryModelNode node, ScopeAnalysis first, ScopeAnalysis second) {
		int firstId = first.arena().id(node);
		int secondId = second.arena().id(node);
		assertThat(first.facts().frame(firstId)).isEqualTo(second.facts().frame(secondId));
		assertThat(first.facts().region(firstId)).isEqualTo(second.facts().region(secondId));
		assertThat(first.facts().environment(firstId)).isEqualTo(second.facts().environment(secondId));
		assertThat(first.facts().resultKind(firstId)).isEqualTo(second.facts().resultKind(secondId));
		assertThat(first.facts().flags(firstId)).isEqualTo(second.facts().flags(secondId));
		assertThat(first.facts().fingerprint(firstId)).isEqualTo(second.facts().fingerprint(secondId));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}
}
